/// </summary>
public sealed class PluginCustomization
{
    /// <summary>
    /// Session-unique opaque identifier. Used by every action that targets a
    /// specific customization. Minted by whoever publishes the customization
    /// (typically the agent host).
    /// </summary>
    [JsonPropertyName("id")]
